import subprocess
import shlex
import re
import logging
import pika

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Allowlist of permitted commands and their allowed argument patterns
ALLOWED_COMMANDS = {
    "python": {
        "allowed_args_pattern": r"^[\w\-./]+\.py(\s+[\w\-./=]+)*$",
        "description": "Run Python scripts",
    },
    "echo": {
        "allowed_args_pattern": r"^[\w\s\-.,]+$",
        "description": "Echo text output",
    },
    "ls": {
        "allowed_args_pattern": r"^[\w\-./\s]*$",
        "description": "List directory contents",
    },
    "cat": {
        "allowed_args_pattern": r"^[\w\-./]+$",
        "description": "Display file contents",
    },
}

# Characters/patterns that indicate shell injection attempts
DANGEROUS_PATTERNS = [
    r"[;&|`$]",       # Shell metacharacters
    r"\$\(",           # Command substitution
    r"\.\.",           # Directory traversal
    r">\s*",           # Output redirection
    r"<\s*",           # Input redirection
    r"\bsudo\b",       # Privilege escalation
    r"\brm\b",         # File deletion
    r"\bchmod\b",      # Permission changes
    r"\bchown\b",      # Ownership changes
    r"\bcurl\b",       # Network requests (unless explicitly allowed)
    r"\bwget\b",       # Network requests
    r"\bnc\b",         # Netcat
    r"\bdd\b",         # Disk operations
    r"\bmkfs\b",       # Filesystem operations
    r"\beval\b",       # Eval
    r"\bexec\b",       # Exec
    r"\\x[0-9a-fA-F]", # Hex escape sequences
    r"\\u[0-9a-fA-F]", # Unicode escape sequences
]


def validate_command(command_string):
    """
    Validate a command string against the allowlist and dangerous patterns.
    Returns (is_valid, sanitized_args_list_or_error_message).
    """
    if not command_string or not isinstance(command_string, str):
        return False, "Empty or invalid command"

    command_string = command_string.strip()

    if not command_string:
        return False, "Empty command after stripping"

    # Check for dangerous patterns in the raw command string
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, command_string):
            return False, f"Dangerous pattern detected: {pattern}"

    # Parse the command safely using shlex (not shell=True)
    try:
        args = shlex.split(command_string)
    except ValueError as e:
        return False, f"Failed to parse command: {e}"

    if not args:
        return False, "No command found after parsing"

    base_command = args[0]

    # Extract just the binary name (handle paths like /usr/bin/python)
    base_command_name = base_command.split("/")[-1]

    # Check if command is in the allowlist
    if base_command_name not in ALLOWED_COMMANDS:
        return False, f"Command '{base_command_name}' is not in the allowlist. Allowed: {list(ALLOWED_COMMANDS.keys())}"

    # Validate arguments against the allowed pattern
    allowed_config = ALLOWED_COMMANDS[base_command_name]
    args_string = " ".join(args[1:]) if len(args) > 1 else ""

    if args_string and not re.match(allowed_config["allowed_args_pattern"], args_string):
        return False, f"Arguments '{args_string}' do not match allowed pattern for '{base_command_name}'"

    # Return the safely parsed argument list (never the raw string)
    return True, args


def execute_command(args_list, timeout=60):
    """
    Execute a validated command with safety constraints.
    Uses subprocess.run with shell=False and a timeout.
    """
    try:
        result = subprocess.run(
            args_list,
            shell=False,          # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=timeout,
            cwd="/tmp",           # Restrict working directory
            env={                 # Minimal environment
                "PATH": "/usr/local/bin:/usr/bin:/bin",
                "HOME": "/tmp",
                "LANG": "C.UTF-8",
            },
        )
        return {
            "success": result.returncode == 0,
            "returncode": result.returncode,
            "stdout": result.stdout[:10000],  # Limit output size
            "stderr": result.stderr[:10000],
        }
    except subprocess.TimeoutExpired:
        return {"success": False, "error": "Command timed out"}
    except Exception as e:
        return {"success": False, "error": str(e)}


def on_message(channel, method_frame, header_frame, body):
    """
    Callback for processing messages from RabbitMQ.
    Validates and safely executes commands.
    """
    delivery_tag = method_frame.delivery_tag

    try:
        command_string = body.decode("utf-8")
    except (UnicodeDecodeError, AttributeError):
        logger.error("Failed to decode message body")
        channel.basic_nack(delivery_tag=delivery_tag, requeue=False)
        return

    logger.info(f"Received job message: {command_string[:100]}...")

    # Validate the command
    is_valid, result = validate_command(command_string)

    if not is_valid:
        logger.warning(f"Rejected command: {result}")
        # Reject the message without requeuing (it will never be valid)
        channel.basic_nack(delivery_tag=delivery_tag, requeue=False)
        return

    # result is the safely parsed args list
    args_list = result
    logger.info(f"Executing validated command: {args_list}")

    exec_result = execute_command(args_list)

    if exec_result["success"]:
        logger.info(f"Command succeeded: stdout={exec_result.get('stdout', '')[:200]}")
        channel.basic_ack(delivery_tag=delivery_tag)
    else:
        logger.error(f"Command failed: {exec_result}")
        # Nack and don't requeue failed commands to avoid infinite loops
        channel.basic_nack(delivery_tag=delivery_tag, requeue=False)


def start_consumer(host="localhost", port=5672, queue_name="job_queue",
                   username="guest", password="guest", prefetch_count=1):
    """
    Start the RabbitMQ consumer with secure message processing.
    """
    credentials = pika.PlainCredentials(username, password)
    connection_params = pika.ConnectionParameters(
        host=host,
        port=port,
        credentials=credentials,
        heartbeat=600,
        blocked_connection_timeout=300,
    )

    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()

    # Declare the queue (idempotent)
    channel.queue_declare(queue=queue_name, durable=True)

    # Only process one message at a time
    channel.basic_qos(prefetch_count=prefetch_count)

    # Set up the consumer
    channel.basic_consume(queue=queue_name, on_message_callback=on_message)

    logger.info(f"Consumer started. Listening on queue '{queue_name}'...")
    logger.info(f"Allowed commands: {list(ALLOWED_COMMANDS.keys())}")

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Consumer interrupted. Shutting down...")
        channel.stop_consuming()
    finally:
        connection.close()
        logger.info("Connection closed.")


if __name__ == "__main__":
    start_consumer()